module RefModule(
    input clk,
    input rst,
    input enable,
    input up_down,
    output reg [2:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst)
        q <= 3'b000;
    else if (enable) begin
        if (up_down)
            q <= q + 1;
        else
            q <= q - 1;
    end
end

endmodule
